class Solution:
    def minPathSum(self, g: List[List[int]]) -> int:
        m, n = len(g), len(g[0])
        dp = g[0][:]
        for j in range(1, n):
            dp[j] += dp[j - 1]
        for i in range(1, m):
            dp[0] += g[i][0]
            for j in range(1, n):
                dp[j] = g[i][j] + min(dp[j], dp[j - 1])
        return dp[-1]

