int minPathSum(int** g, int m, int n) {
    int dp[n];
    for (int j = 0; j < n; j++) dp[j] = g[0][j];
    for (int j = 1; j < n; j++) dp[j] += dp[j - 1];
    for (int i = 1; i < m; i++) {
        dp[0] += g[i][0];
        for (int j = 1; j < n; j++) {
            int v = g[i][j];
            dp[j] = v + (dp[j] < dp[j - 1] ? dp[j] : dp[j - 1]);
        }
    }
    return dp[n - 1];
}
